scwin.f_Retrieve = async function () {
  // 검색조건 필수 입력 체크
  if (!(await $c.gus.cfValidate($p, [lc_lobranCd, ica_wrkDt]))) {
    return;
  }
  $c.sbm.execute($p, sbm_retrieve);
};
